    "description": "Missing admin flag setup in endpoint query function. Comparing with similar admin-only endpoints (e.g., comment-replies.js:read endpoint), this endpoint must set frame.options.isAdmin = true before calling the controller. Without this, the controller and service layers won't know the request is from an admin, potentially leading to incorrect access control and permission checks. This is a functional bug that breaks admin authorization for the likes browsing feature.",
    "fix_patch": "--- a/ghost/core/core/server/api/endpoints/comment-likes.js
+++ b/ghost/core/core/server/api/endpoints/comment-likes.js
@@ -26,7 +26,8 @@
             docName: 'comments'
         },
         query(frame) {
+            frame.options.isAdmin = true;
             return commentsService.controller.getCommentLikes(frame);
         }
     }
 };
"
  },
  {
    "file": "ghost/core/core/server/services/comments/comments-controller.js",
    "line": 369,
    "severity": "high",
    "description": "Controller method only passes partial options to service. The getCommentLikes method extracts only page and limit from frame.options and passes them to the service. This is inconsistent with other controller methods that pass the complete options (e.g., read method at line 195 passes full frame.options). This prevents important context flags like isAdmin, context.member, and transaction handles from reaching the service layer, breaking admin authorization and potentially causing data access violations.",
    "fix_patch": "--- a/ghost/core/core/server/services/comments/comments-controller.js
+++ b/ghost/core/core/server/services/comments/comments-controller.js
@@ -367,11 +367,12 @@
     /**
      * Get likes for a specific comment (admin only)
      * @param {Frame} frame
      */
     async getCommentLikes(frame) {
         const commentId = frame.options.id;
-        return await this.service.getCommentLikes(commentId, {
-            page: frame.options.page,
-            limit: frame.options.limit
-        });
+        const options = _.omit(frame.options, 'id');
+        return await this.service.getCommentLikes(commentId, options);
     }
 };
"
  },
  {
    "file": "ghost/core/core/server/services/comments/comments-service.js",
    "line": 266,
    "severity": "high",
    "description": "The findOne call does not pass options parameter. When checking if a comment exists, the code should pass options to findOne (including isAdmin, context, and transaction handles) similar to how getCommentByID does at line 291. Without passing options, the model layer cannot perform proper access control checks or apply admin context, potentially exposing data that should be protected.",
    "fix_patch": "--- a/ghost/core/core/server/services/comments/comments-service.js
+++ b/ghost/core/core/server/services/comments/comments-service.js
@@ -264,7 +264,7 @@
      */
     async getCommentLikes(commentId, options = {}) {
-        const comment = await this.models.Comment.findOne({id: commentId});
+        const comment = await this.models.Comment.findOne({id: commentId}, options);
         if (!comment) {
             throw new errors.NotFoundError({
                 message: tpl(messages.commentNotFound)
"
  },
  {
    "file": "ghost/core/core/server/services/comments/comments-service.js",
    "line": 274,
    "severity": "high",
    "description": "The findPage call does not pass the isAdmin flag to the models layer. Comparing with similar admin methods (e.g., getAdminComments at line 219 and getAdminAllComments at line 202), admin-only methods must pass isAdmin: true to findPage so the models layer knows to apply appropriate filtering and permission checks. Without this flag, the models layer may return incorrect data or bypass access control for admin requests.",
    "fix_patch": "--- a/ghost/core/core/server/services/comments/comments-service.js
+++ b/ghost/core/core/server/services/comments/comments-service.js
@@ -273,12 +273,13 @@
         const {page, limit} = options;
         const result = await this.models.CommentLike.findPage({
             filter: `comment_id:'${commentId}'`,
             withRelated: ['member'],
             order: 'created_at desc',
             page,
-            limit
+            limit,
+            isAdmin: true
         });

         return result;
     }
"
  }
]

